13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_TYPES = ["rune", "moonstone"];
26	const COMPONENTS_PER_BLOCK = 3;
27	const COMPONENT_BLOCK_BASE = 60;
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FOLLOW_UP_CONTRACTS_THRESHOLD = 1;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	export interface Policy {
37	  items: Item[];
38	}
39	
40	export interface Damage {
41	  itemType: string;
42	  amount: number;
43	}
44	
45	export interface Incident {
46	  damages: Damage[];
47	}
48	
49	export interface ClaimResult {
50	  payout: number;
51	  remainingCap: number;
52	}
53	
54	const INSURANCE_VALUES: Record<string, number> = {
55	  sword: 1000,
56	  amulet: 600,
57	  staff: 800,
58	  potion: 400,
59	  rune: 250,
60	  moonstone: 250,
61	};
62	const DEDUCTIBLE = 100;
63	const CAP_MULTIPLIER = 2;
64	
65	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
66	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
67	
68	export function claim(policy: Policy, incident: Incident): ClaimResult {
69	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
70	  const cap = CAP_MULTIPLIER * insuranceSum;
71	  const payout = incident.damages.reduce((sum, damage) => {
72	    const item = policy.items.find((policyItem) => policyItem.type === damage.itemType);
73	    const reimbursable = (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
74	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
75	      : damage.amount;
76	    return sum + Math.max(0, reimbursable - DEDUCTIBLE);
77	  }, 0);
78	  return { payout, remainingCap: cap - payout };
79	}
