81	export function quote(customer: Customer, items: Item[]): number {
82	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
83	    items.filter(applies).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
84	
85	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
86	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
87	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
88	    const count = items.filter((item) => item.type === componentType).length;
89	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
90	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
91	  }, 0);
92	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
93	  const highEnchantmentSurcharge = percentageSurcharge(
94	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
95	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
96	  );
97	  const adjustedBase = baseSum + blockAdjustment;
98	  const proportionalDiscount = (rate: number, qualifies: boolean): number => (qualifies ? adjustedBase * rate : 0);
99	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
100	  const loyaltyDiscount = proportionalDiscount(LOYALTY_DISCOUNT_RATE, customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD);
101	  const followUpDiscount = proportionalDiscount(FOLLOW_UP_DISCOUNT_RATE, (customer.previousContracts ?? 0) >= FOLLOW_UP_CONTRACTS_THRESHOLD);
102	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
103	}
